(()=>{(function(){"use strict";const a={beran:{name:"Beran",emoji:"\u2648",element:"Ohe\u0148",barva:"#e74c3c",focus:"svou odvahu a p\u0159irozenou ak\u010Dnost",vizObraz:"jasn\xFD plamen ve va\u0161em srdci \u2014 \u010Dist\xFD, pevn\xFD a nekontrolovateln\xFD",mantraSlovo:"odvaze",ruler:"Mars",uzemeniVeta:"C\xEDt\xEDte Martovu energii \u2014 p\u0159ipravenou k akci, ne k \u010Dek\xE1n\xED.",uzavreniVeta:"Mars stoj\xED za v\xE1mi. Jdete vp\u0159ed.",journalQ:"Kde jsem dnes jednal/a okam\u017Eit\u011B a spr\xE1vn\u011B \u2014 bez p\u0159\xEDli\u0161n\xE9ho p\u0159em\xFD\u0161len\xED?"},byk:{name:"Byk",emoji:"\u2649",element:"Zem\u011B",barva:"#27ae60",focus:"svou stabilitu a propojen\xED s p\u0159\xEDrodou",vizObraz:"hlubok\xE9 ko\u0159eny stromu, kter\xE9 dr\u017E\xED pevn\u011B v zemi bez ohledu na v\xEDtr",mantraSlovo:"stabilit\u011B",ruler:"Venu\u0161e",uzemeniVeta:"C\xEDt\xEDte pevnou zemi pod nohama \u2014 v\xE1\u0161 p\u0159irozen\xFD zdroj s\xEDly.",uzavreniVeta:"Venu\u0161e v\xE1s prov\xE1z\xED ka\u017Ed\xFDm klidn\xFDm krokem kup\u0159edu.",journalQ:"Co mi dnes p\u0159ineslo skute\u010Dn\xFD pocit bezpe\u010D\xED a vnit\u0159n\xEDho klidu?"},blizenci:{name:"Bl\xED\u017Eenci",emoji:"\u264A",element:"Vzduch",barva:"#f39c12",focus:"svou zv\xEDdavost a schopnost spojovat protiklady",vizObraz:"\u010Dist\xFD horsk\xFD vzduch, kter\xFD pro\u010Di\u0161\u0165uje ka\u017Edou my\u0161lenku",mantraSlovo:"jasnosti",ruler:"Merkur",uzemeniVeta:"V\xE1\u0161 Merkurovsk\xFD um se \u010Dist\xED jako vzduch po de\u0161ti \u2014 pohybliv\xFD a jasn\xFD.",uzavreniVeta:"Merkur nese va\u0161e z\xE1m\u011Bry p\u0159esn\u011B tam, kam maj\xED j\xEDt.",journalQ:"Jakou neo\u010Dek\xE1vanou spojitost jsem dnes zahl\xE9dl/a \u2014 a co by mohla znamenat?"},rak:{name:"Rak",emoji:"\u264B",element:"Voda",barva:"#2980b9",focus:"svou intuici a schopnost pe\u010Dovat o druh\xE9 i o sebe",vizObraz:"klidn\xE1 hladina jezera, kter\xE1 zrcadl\xED hv\u011Bzdy dokonale",mantraSlovo:"intuici",ruler:"M\u011Bs\xEDc",uzemeniVeta:"Jste v domovin\u011B M\u011Bs\xEDce \u2014 \u017E\xE1dn\xE9 jin\xE9 znamen\xED nec\xEDt\xED lun\xE1rn\xED energii tak p\u0159irozen\u011B jako vy.",uzavreniVeta:"V\xE1\u0161 M\u011Bs\xEDc v\xE1m otev\u0159el p\u0159esn\u011B to, co jste pot\u0159eboval/a vid\u011Bt.",journalQ:"Co mi dnes \u0159ekla moje intuice jako prvn\xED \u2014 a jak jsem na ni reagoval/a?"},lev:{name:"Lev",emoji:"\u264C",element:"Ohe\u0148",barva:"#e67e22",focus:"svou tvo\u0159ivost a p\u0159irozen\xE9 sebevyj\xE1d\u0159en\xED",vizObraz:"zlat\xE9 slune\u010Dn\xED sv\u011Btlo vych\xE1zej\xEDc\xED p\u0159\xEDmo z va\u0161eho srdce",mantraSlovo:"tvo\u0159ivosti",ruler:"Slunce",uzemeniVeta:"Slune\u010Dn\xED z\xE1\u0159e ve va\u0161em srdci sv\xEDt\xED i v noci \u2014 to je v\xE1\u0161 p\u0159irozen\xFD stav.",uzavreniVeta:"Slune\u010Dn\xED energie z\u016Fst\xE1v\xE1 ve v\xE1s \u2014 je\u0161t\u011B dlouho po zhasnut\xE9 sv\xED\u010Dce.",journalQ:"Kde jsem dnes p\u0159irozen\u011B zaz\xE1\u0159il/a \u2014 a jak to ovlivnilo lidi kolem m\u011B?"},panna:{name:"Panna",emoji:"\u264D",element:"Zem\u011B",barva:"#8e44ad",focus:"svou preciznost a schopnost vid\u011Bt kr\xE1su v detailech",vizObraz:"\u010Dist\xE1 pr\u016Fzra\u010Dn\xE1 voda tekouc\xED p\u0159es hladk\xE9 kameny",mantraSlovo:"p\xE9\u010Di",ruler:"Merkur",uzemeniVeta:"Va\u0161e p\u0159irozen\xE1 preciznost je dar \u2014 nechte ji pracovat ti\u0161e a p\u0159esn\u011B pro v\xE1s.",uzavreniVeta:"Ka\u017Ed\xFD detail, jemu\u017E v\u011Bnujete p\xE9\u010Di, roste a p\u0159in\xE1\u0161\xED ovoce.",journalQ:"Jak\xFD detail jsem dnes zachytil/a, kter\xFD ostatn\xED p\u0159ehl\xE9dli \u2014 a co to odhalilo?"},vahy:{name:"V\xE1hy",emoji:"\u264E",element:"Vzduch",barva:"#16a085",focus:"svou touhu po harmonii ve vztaz\xEDch i v sob\u011B",vizObraz:"dokonale vyv\xE1\u017Een\xE9 zlat\xE9 v\xE1hy klidn\u011B spo\u010D\xEDvaj\xEDc\xED ve st\u0159edu",mantraSlovo:"harmonii",ruler:"Venu\u0161e",uzemeniVeta:"Va\u0161e vnit\u0159n\xED v\xE1hy se ti\u0161e vyrovn\xE1vaj\xED \u2014 Venu\u0161e v\xE1s v tom podporuje.",uzavreniVeta:"Harmonie, po kter\xE9 tou\u017E\xEDte, v\u017Edy za\u010D\xEDn\xE1 uvnit\u0159 v\xE1s samotn\xFDch.",journalQ:"Kde jsem dnes vn\xE1\u0161/a rovnov\xE1hu do vztah\u016F nebo situac\xED \u2014 v\u011Bdom\u011B nebo instinktivn\u011B?"},stir:{name:"\u0160t\xEDr",emoji:"\u264F",element:"Voda",barva:"#c0392b",focus:"svou hloubku a schopnost proch\xE1zet transformac\xED",vizObraz:"f\xE9nix stoupaj\xEDc\xED z temn\xE9 vody \u2014 prom\u011Bn\u011Bn\xFD, siln\u011Bj\u0161\xED, svobodn\xFD",mantraSlovo:"transformaci",ruler:"Pluto",uzemeniVeta:"Temnota v\xE1s nestra\u0161\xED \u2014 vy z n\xED p\u0159irozen\u011B \u010Derp\xE1te svou nejv\u011Bt\u0161\xED s\xEDlu.",uzavreniVeta:"Pluto stvrdil va\u0161i prom\u011Bnu. Jste siln\u011Bj\u0161\xED, ne\u017E jste byli p\u0159i za\u010D\xE1tku tohoto ritu\xE1lu.",journalQ:"\u010Ceho jsem se dnes ochoten/ochotna pustit, co jsem d\u0159\xEDve pova\u017Eoval/a za ned\xEDlnou sou\u010D\xE1st sebe?"},strelec:{name:"St\u0159elec",emoji:"\u2650",element:"Ohe\u0148",barva:"#d35400",focus:"svou touhu po expanzi, pravd\u011B a svobod\u011B",vizObraz:"\u0161\xEDp let\xEDc\xED p\u0159esn\u011B a s jistotou k vzd\xE1len\xE9mu c\xEDli",mantraSlovo:"svobod\u011B",ruler:"Jupiter",uzemeniVeta:"Jupiter roz\u0161i\u0159uje v\xE1\u0161 obzor \u2014 c\xEDt\xEDte tu prostorovost a svobodu?",uzavreniVeta:"V\xE1\u0161 \u0161\xEDp let\xED. Svoboda je vnit\u0159n\xED stav \u2014 a vy ji nos\xEDte st\xE1le v sob\u011B.",journalQ:"Kam p\u0159esn\u011B m\xED\u0159\xED m\u016Fj z\xE1m\u011Br \u2014 a je to st\xE1le pravda a svoboda, po n\xED\u017E skute\u010Dn\u011B tou\u017E\xEDm?"},kozoroh:{name:"Kozoroh",emoji:"\u2651",element:"Zem\u011B",barva:"#7f8c8d",focus:"svou discipl\xEDnu a vizi dlouhodob\xE9ho z\xE1m\u011Bru",vizObraz:"hora, kter\xE1 stoj\xED pevn\u011B tis\xEDce let \u2014 neochv\u011Bjn\xE1 a majest\xE1tn\xED",mantraSlovo:"vytrvalosti",ruler:"Saturn",uzemeniVeta:"Saturn v\xE1m d\xE1v\xE1 dar trp\u011Blivosti \u2014 nejcenn\u011Bj\u0161\xED ze v\u0161ech zdroj\u016F.",uzavreniVeta:"K\xE1men po kameni, krok po kroku \u2014 tak se stav\xED hory i cel\xE9 \u017Eivoty.",journalQ:"Jak\xFD dlouhodob\xFD z\xE1m\u011Br jsem dnes posunul/a o jeden konkr\xE9tn\xED, m\u011B\u0159iteln\xFD krok vp\u0159ed?"},vodnar:{name:"Vodn\xE1\u0159",emoji:"\u2652",element:"Vzduch",barva:"#2471a3",focus:"svou originalitu a vizi lep\u0161\xEDho sv\u011Bta",vizObraz:"hv\u011Bzdy propojen\xE9 sv\u011Bteln\xFDmi vl\xE1kny do jednoho velk\xE9ho vzoru",mantraSlovo:"vizi",ruler:"Uran",uzemeniVeta:"Va\u0161e vize p\u0159edb\xEDh\xE1 dobu \u2014 Uran v\xE1s pos\xEDl\xE1 tam, kde ostatn\xED je\u0161t\u011B nejsou.",uzavreniVeta:"Uran p\u0159in\xE1\u0161\xED revoluci. Vy ji vedete \u2014 klidn\u011B, v\u011Bdom\u011B, s p\u0159ehledem.",journalQ:"Jakou neobvyklou my\u0161lenku jsem dnes zachytil/a \u2014 a co by se stalo, kdybych ji naplno sledoval/a?"},ryby:{name:"Ryby",emoji:"\u2653",element:"Voda",barva:"#1a5276",focus:"sv\u016Fj soucit a intuici p\u0159esahuj\xEDc\xED rozum",vizObraz:"tich\xE9 hlubok\xE9 mo\u0159e, jeho\u017E dno skr\xFDv\xE1 starod\xE1vnou moudrost",mantraSlovo:"soucitu",ruler:"Neptun",uzemeniVeta:"Neptunova hlubina ve v\xE1s je bezpe\u010Dn\xE1 \u2014 nechte ji proz\xE1\u0159it va\u0161e tu\u0161en\xED.",uzavreniVeta:"Va\u0161e intuice je most mezi sv\u011Bty. D\u016Fv\u011B\u0159ujte j\xED \u2014 vede v\xE1s p\u0159esn\u011Bji ne\u017E jak\xE1koliv logika.",journalQ:"Jak\xE9mu snu, pocitu nebo tu\u0161en\xED jsem dnes v\u011Bnoval/a pozornost \u2014 a co mi tich\xFDm hlasem \u0159\xEDkal?"}},n={"new-moon":{nazevPrefix:"Ritu\xE1l z\xE1m\u011Br\u016F",tema:"Nov\xFD za\u010D\xE1tek \u2014 set\xED z\xE1m\u011Br\u016F do temnoty",popis:e=>`Novolun\xED je kosmick\xFDm resetem. Pr\xE1zdn\xFD M\u011Bs\xEDc p\u0159ij\xEDm\xE1 z\xE1m\u011Bry jako \xFArodn\xE1 p\u016Fda sem\xEDnka. ${e.element} v\xE1s dnes podporuje v formulov\xE1n\xED toho, co skute\u010Dn\u011B chcete p\u0159iv\xE9st do sv\xE9ho \u017Eivota.`,prepList:["Sv\xED\u010Dka (b\xEDl\xE1 nebo st\u0159\xEDbrn\xE1)","Pap\xEDr a tu\u017Eka","Klidn\xE9 m\xEDsto na 10 minut","Sklenka vody"],duration:"8\u201310 minut",kroky:[{title:"Uzem\u011Bn\xED",text:e=>`Rozsv\u011B\u0165te sv\xED\u010Dku a sedn\u011Bte si pohodln\u011B. T\u0159ikr\xE1t zhluboka d\xFDchejte \u2014 n\xE1dech nosem na 4 doby, zadr\u017Ete na 4, v\xFDdech \xFAsty na 6. S ka\u017Ed\xFDm v\xFDdechem pus\u0165te nap\u011Bt\xED tohoto dne. Nechte ticho novolun\u011Bn\xED, aby v\xE1s zahalilo jako p\u0159ikr\xFDvka. ${e.uzemeniVeta}`,subtext:"P\u0159\xEDprava posv\xE1tn\xE9ho prostoru"},{title:"Z\xE1m\u011Br",text:e=>`Polo\u017Ete ruku na srdce. V tichu se zeptejte: "Co chci p\u0159iv\xE9st do sv\xE9ho \u017Eivota v p\u0159\xED\u0161t\xEDch 29 dnech?" Nechte ${e.focus} mluvit jako prvn\xED \u2014 bez cenzury, bez posuzov\xE1n\xED. Naslouchejte.`,subtext:"\u010Cas vnit\u0159n\xEDho naslouch\xE1n\xED"},{title:"Vizualizace",text:e=>`Zav\u0159ete o\u010Di. P\u0159edstavte si ${e.vizObraz}. Pak si p\u0159edstavte, jak tento obraz stoup\xE1 k temn\xE9mu M\u011Bs\xEDci na obloze. M\u011Bs\xEDc p\u0159ij\xEDm\xE1 v\xE1\u0161 z\xE1m\u011Br jako sem\xEDnko do posv\xE1tn\xE9 p\u016Fdy. Vydr\u017Ete v tomto obrazci 2 minuty.`,subtext:"Set\xED z\xE1m\u011Br\u016F do lun\xE1rn\xEDho pole"},{title:"Fyzick\xFD \xFAkon",text:e=>'Vezm\u011Bte pap\xEDr a napi\u0161te 3 z\xE1m\u011Bry v p\u0159\xEDtomn\xE9m \u010Dase \u2014 jako by se ji\u017E d\u011Bly. Za\u010Dn\u011Bte slovy "Jsem\u2026", "M\xE1m\u2026", nebo "P\u0159ij\xEDm\xE1m\u2026". Pap\xEDr p\u0159elo\u017Ete a uschovejte na bezpe\u010Dn\xE9m m\xEDst\u011B a\u017E do \xDApl\u0148ku \u2014 a sledujte, jak se z\xE1m\u011Bry napl\u0148uj\xED.',subtext:"Z\xE1m\u011Bry zapsan\xE9 se st\xE1vaj\xED realitou"},{title:"Mantra",text:e=>`T\u0159ikr\xE1t opakujte nahlas nebo v duchu:

\u201EV ${e.mantraSlovo} a tichu novolun\xED zas\xEDv\xE1m svou budoucnost.
Nech\u0165 p\u0159ijde v prav\xFD \u010Das \u2014 pod veden\xEDm ${e.ruler}."`,subtext:"Opakujte t\u0159ikr\xE1t \u2014 s pln\xFDm p\u0159esv\u011Bd\u010Den\xEDm"},{title:"Uzav\u0159en\xED",text:e=>`Pod\u011Bkujte M\u011Bs\xEDci za jeho skrytou s\xEDlu temnoty. Pod\u011Bkujte sob\u011B za to, \u017Ee jste ud\u011Blali \u010Das pro tuto praxi. ${e.uzavreniVeta} Zhasn\u011Bte sv\xED\u010Dku v\u011Bdom\u011B, jako akt uzav\u0159en\xED posv\xE1tn\xE9ho prostoru. V\xE1\u0161 z\xE1m\u011Br byl p\u0159ijat.`,subtext:"Ritu\xE1l je dokon\u010Den"}],journalPrompts:e=>["Co se ve mn\u011B pohnulo, kdy\u017E jsem formuloval/a z\xE1m\u011Bry? Co m\u011B p\u0159ekvapilo?","Jak\xE9 \u010D\xE1sti z\xE1m\u011Bru mi jde nejh\u016F\u0159 uv\u011B\u0159it \u2014 a co to \u0159\xEDk\xE1 o m\xE9 v\xED\u0159e v sebe?","Co mus\xEDm pustit, aby nov\xFD za\u010D\xE1tek mohl p\u0159ij\xEDt?",e.journalQ]},"waxing-crescent":{nazevPrefix:"Ritu\xE1l prvn\xEDho kroku",tema:"Dor\u016Fstaj\xEDc\xED srpek \u2014 odvaha k prvn\xED akci",popis:e=>`Tenk\xFD srpek M\u011Bs\xEDce se zjevuje jako prvn\xED p\u0159\xEDslib. Je \u010Das jednat na z\xE1klad\u011B z\xE1m\u011Br\u016F. Va\u0161e ${e.element.toLowerCase()} v\xE1s poh\xE1n\xED \u2014 mal\xFD, ale re\xE1ln\xFD krok dnes m\u016F\u017Ee zm\u011Bnit v\u0161e.`,prepList:["Sv\xED\u010Dka","Pap\xEDr a tu\u017Eka","Pohodln\xE9 m\xEDsto k sezen\xED"],duration:"7\u20139 minut",kroky:[{title:"Uzem\u011Bn\xED",text:e=>`Rozsv\u011B\u0165te sv\xED\u010Dku. T\u0159ikr\xE1t zhluboka d\xFDchejte. S ka\u017Ed\xFDm v\xFDdechem propus\u0165te jeden strach nebo pochybnost. Nechte dor\u016Fstaj\xEDc\xED energii M\u011Bs\xEDce proudit va\u0161im t\u011Blem jako prvn\xED rann\xED sv\u011Btlo. ${e.uzemeniVeta}`,subtext:"P\u0159\xEDprava na akci"},{title:"Z\xE1m\u011Br",text:e=>`Polo\u017Ete ruku na hrudn\xEDk. Vzpome\u0148te na z\xE1m\u011Bry ze za\u010D\xE1tku cyklu. Zeptejte se: "Jak\xFD JEDEN konkr\xE9tn\xED krok mohu ud\u011Blat je\u0161t\u011B dnes?" Nechte ${e.focus} v\xE1m uk\xE1zat cestu. V\u011B\u0159te prvn\xED my\u0161lence, kter\xE1 p\u0159ijde.`,subtext:"Propojen\xED se z\xE1m\u011Brem"},{title:"Vizualizace",text:e=>`Zav\u0159ete o\u010Di. P\u0159edstavte si ${e.vizObraz}. Tento obraz v\xE1s vede jako lamp\xE1\u0161 v semi-tm\u011B. Nyn\xED si vizualizujte sebe, jak d\u011Bl\xE1te ten jeden krok \u2014 s lehkost\xED, s jistotou, bez v\xE1h\xE1n\xED. C\xEDt\u011Bte tu lehkost v cel\xE9m t\u011Ble.`,subtext:"Vizualizace odhodl\xE1n\xED"},{title:"Fyzick\xFD \xFAkon",text:e=>'Napi\u0161te na pap\xEDr: "Dnes ud\u011Bl\xE1m: ___________." Vypl\u0148te jednu konkr\xE9tn\xED, splnitelnou akci. Pak tento z\xE1vazek nechte na viditeln\xE9m m\xEDst\u011B jako p\u0159ipom\xEDnku. A tu akci ud\u011Blejte \u2014 je\u0161t\u011B dnes.',subtext:"Z\xE1vazek stvrzen\xFD p\xEDsmem"},{title:"Mantra",text:e=>`T\u0159ikr\xE1t opakujte:

\u201EV ${e.mantraSlovo} kon\xE1m prvn\xED krok.
M\u011Bs\xEDc roste se mnou \u2014 a ${e.ruler} mi d\xE1v\xE1 s\xEDlu."`,subtext:"Opakujte t\u0159ikr\xE1t"},{title:"Uzav\u0159en\xED",text:e=>`Pod\u011Bkujte si za odvahu za\u010D\xEDt. Ka\u017Ed\xE1 velk\xE1 cesta za\u010D\xEDn\xE1 krokem, kter\xFD vypad\xE1 mal\xFD. ${e.uzavreniVeta} Zhasn\u011Bte sv\xED\u010Dku v\u011Bdom\u011B. Va\u0161e odhodl\xE1n\xED bylo stvrzeno.`,subtext:"Ritu\xE1l dokon\u010Den"}],journalPrompts:e=>["Co m\u011B v prvn\xEDm kroku nejv\xEDce brzd\xED? Je to re\xE1ln\xE1 p\u0159ek\xE1\u017Eka, nebo jen strach z nezn\xE1m\xE9ho?","Jak se budu c\xEDtit, a\u017E ten krok ud\u011Bl\xE1m \u2014 i kdyby se uk\xE1zalo, \u017Ee byl \u0161patn\xFD?","Komu mohu \u0159\xEDct o sv\xE9m z\xE1m\u011Bru, aby m\u011B ve spr\xE1vnou chv\xEDli podpo\u0159il/a?",e.journalQ]},"first-quarter":{nazevPrefix:"Ritu\xE1l rozhodnosti",tema:"Prvn\xED \u010Dtvr\u0165 \u2014 v\u016Fle skrze p\u0159ek\xE1\u017Eky",popis:e=>`P\u0159esn\u011B polovina M\u011Bs\xEDce je osv\u011Btlena \u2014 symbolick\xE9 nap\u011Bt\xED mezi z\xE1m\u011Brem a realitou. P\u0159ich\xE1z\xED prvn\xED odpor. Va\u0161e ${e.element.toLowerCase()} v\xE1m d\xE1v\xE1 s\xEDlu skrz p\u0159ek\xE1\u017Eku proj\xEDt, ne se vr\xE1tit.`,prepList:["Sv\xED\u010Dka","Pap\xEDr a tu\u017Eka","Tich\xE9 m\xEDsto"],duration:"8\u201310 minut",kroky:[{title:"Uzem\u011Bn\xED",text:e=>`Rozsv\u011B\u0165te sv\xED\u010Dku. Stoupn\u011Bte si pevn\u011B nohama na zem. T\u0159ikr\xE1t zhluboka d\xFDchejte. C\xEDt\u011Bte stabilitu pod sebou. \u017D\xE1dn\xE1 p\u0159ek\xE1\u017Eka v\xE1s nevyko\u0159\xED \u2014 stoj\xEDte pevn\u011B jako strom. ${e.uzemeniVeta}`,subtext:"Uzem\u011Bn\xED ve v\u016Fli"},{title:"Z\xE1m\u011Br",text:e=>`Zav\u0159ete o\u010Di a pojmenujte jednu p\u0159ek\xE1\u017Eku, kter\xE1 v\xE1m v tuto chv\xEDli stoj\xED v cest\u011B. Bu\u010Fte p\u0159esn\xED \u2014 ne "nem\xE1m \u010Das", ale "konkr\xE9tn\u011B XY m\u011B blokuje, proto\u017Ee..." Nechte ${e.focus} odhalit skute\u010Dnou p\u0159\xED\u010Dinu.`,subtext:"Pojmenov\xE1n\xED p\u0159ek\xE1\u017Eky"},{title:"Vizualizace",text:e=>`Zav\u0159ete o\u010Di. P\u0159edstavte si ${e.vizObraz}. Nyn\xED si p\u0159edstavte tu p\u0159ek\xE1\u017Eku jako ze\u010F p\u0159ed v\xE1mi. A pak si p\u0159edstavte, jak ji p\u0159ekra\u010Dujete \u2014 krok za krokem. Soust\u0159e\u010Fte se ne na ze\u010F, ale na to, jak se c\xEDt\xEDte na druh\xE9 stran\u011B.`,subtext:"Vizualizace pr\u016Fchodu"},{title:"Fyzick\xFD \xFAkon",text:e=>'Napi\u0161te p\u0159ek\xE1\u017Eku na pap\xEDr. Pod ni napi\u0161te: "Moje \u0159e\u0161en\xED: ___________." Pap\xEDr p\u0159elo\u017Ete na p\u016Fl \u2014 symbolicky p\u0159ekon\xE1v\xE1te tu hranici. Uschovejte nebo vyho\u010Fte dle pocitu. P\u0159ek\xE1\u017Eka zapsan\xE1 je p\u0159ek\xE1\u017Eka nap\u016Fl vy\u0159e\u0161en\xE1.',subtext:"Symbolick\xE9 p\u0159ekon\xE1n\xED hranice"},{title:"Mantra",text:e=>`T\u0159ikr\xE1t opakujte:

\u201EV ${e.mantraSlovo} a odhodl\xE1n\xED proch\xE1z\xEDm p\u0159ek\xE1\u017Ekou.
Nic m\u011B nezastavuje \u2014 ${e.ruler} stoj\xED za mnou."`,subtext:"Opakujte t\u0159ikr\xE1t s p\u0159esv\u011Bd\u010Den\xEDm"},{title:"Uzav\u0159en\xED",text:e=>`Pod\u011Bkujte si za odvahu pojmenovat to, co v\xE1s brzd\xED. P\u0159ek\xE1\u017Eka pojmenovan\xE1 je nap\u016Fl p\u0159ekonan\xE1. ${e.uzavreniVeta} Zhasn\u011Bte sv\xED\u010Dku. Jdete d\xE1l.`,subtext:"Ritu\xE1l dokon\u010Den"}],journalPrompts:e=>["Co tato p\u0159ek\xE1\u017Eka \u0159\xEDk\xE1 o m\xFDch skute\u010Dn\xFDch hodnot\xE1ch a o tom, co opravdu chci?","Kdo nebo co mi v minulosti pomohlo p\u0159ekonat podobnou situaci?","Jak vypad\xE1 verze m\u011B, kter\xE1 stoj\xED na druh\xE9 stran\u011B t\xE9to v\xFDzvy?",e.journalQ]},"waxing-gibbous":{nazevPrefix:"Ritu\xE1l vylad\u011Bn\xED",tema:"Dor\u016Fstaj\xEDc\xED m\u011Bs\xEDc \u2014 zdokonalov\xE1n\xED a vytrvalost",popis:e=>`M\u011Bs\xEDc je t\xE9m\u011B\u0159 pln\xFD a energie kulminuje. Je \u010Das doladit, ne za\u010D\xEDnat znovu. Va\u0161e ${e.element.toLowerCase()} v\xE1m pom\xE1h\xE1 vid\u011Bt, co funguje, a s p\xE9\u010D\xED to dov\xE9st k dokonalosti.`,prepList:["Sv\xED\u010Dka","Den\xEDk nebo pap\xEDr","Klidn\xE9 m\xEDsto"],duration:"7\u20139 minut",kroky:[{title:"Uzem\u011Bn\xED",text:e=>`Rozsv\u011B\u0165te sv\xED\u010Dku. T\u0159ikr\xE1t zhluboka d\xFDchejte \u2014 s v\u011Bdomou vd\u011B\u010Dnost\xED za to, jak daleko jste od novolun\u011Bn\xED dosp\u011Bli. C\xEDt\u011Bte momentum tohoto cyklu: jsou za v\xE1mi t\u0159i \u010Dtvrtiny cesty. ${e.uzemeniVeta}`,subtext:"Vd\u011B\u010Dn\xE9 uzem\u011Bn\xED"},{title:"Z\xE1m\u011Br",text:e=>`Vzpome\u0148te na z\xE1m\u011Br tohoto cyklu. Zeptejte se: "Co funguje v\xFDborn\u011B? A co pot\u0159ebuje malou, p\u0159esnou korekci?" Nechte ${e.focus} v\xE1m uk\xE1zat, kde je prostor pro zdokonalen\xED. Mal\xE9 vylad\u011Bn\xED m\u016F\u017Ee zm\u011Bnit v\u0161e.`,subtext:"Reflexe pokroku a korekce"},{title:"Vizualizace",text:e=>`Zav\u0159ete o\u010Di. P\u0159edstavte si ${e.vizObraz}. Nyn\xED si p\u0159edstavte sv\u016Fj z\xE1m\u011Br jako 90% dokon\u010Den\xE9 um\u011Bleck\xE9 d\xEDlo \u2014 jak\xFD detail chyb\xED? Co jej dokonale dokon\u010D\xED? Vizualizujte v\xFDsledek s precizn\xED, radostnou jasnost\xED.`,subtext:"Vizualizace dokon\u010Den\xED"},{title:"Fyzick\xFD \xFAkon",text:e=>'Napi\u0161te jednu konkr\xE9tn\xED v\u011Bc, kterou vylad\xEDte nebo dokon\u010D\xEDte p\u0159ed \xDApl\u0148kem. Bu\u010Fte co nejkonkr\xE9tn\u011Bj\u0161\xED: ne "zlep\u0161\xEDm p\u0159\xEDstup", ale "ud\u011Bl\xE1m XY konkr\xE9tn\u011B dnes do 18:00." P\u0159esnost je v t\xE9to f\xE1zi nejsiln\u011Bj\u0161\xED zbran\xED.',subtext:"Konkr\xE9tn\xED z\xE1vazek k dokon\u010Den\xED"},{title:"Mantra",text:e=>`T\u0159ikr\xE1t opakujte:

\u201EV ${e.mantraSlovo} a p\u0159esnosti dosahuji sv\xE9ho c\xEDle.
Jsem t\xE9m\u011B\u0159 tam \u2014 ${e.ruler} mi ukazuje posledn\xED krok."`,subtext:"Opakujte t\u0159ikr\xE1t"},{title:"Uzav\u0159en\xED",text:e=>`Pod\u011Bkujte si za vytrvalost \u2014 vydr\u017Eeli jste cel\xFD tento cyklus. \xDApln\u011Bk p\u0159ich\xE1z\xED a vy jste p\u0159ipraveni. ${e.uzavreniVeta} Zhasn\u011Bte sv\xED\u010Dku. Posledn\xED krok v\xE1s \u010Dek\xE1.`,subtext:"Ritu\xE1l dokon\u010Den"}],journalPrompts:e=>["Co m\u011B v tomto cyklu nejv\xEDce p\u0159ekvapilo \u2014 v dobr\xE9m i v n\xE1ro\u010Dn\xE9m?","Jak\xFD jeden detail, pokud ho vylad\xEDm, posune cel\xFD z\xE1m\u011Br na jinou \xFArove\u0148?","Jak se budu c\xEDtit p\u0159i \xDApl\u0148ku, a\u017E to bude hotov\xE9?",e.journalQ]},"full-moon":{nazevPrefix:"Ritu\xE1l uvoln\u011Bn\xED",tema:"\xDApln\u011Bk \u2014 vrchol energie, oslava a propu\u0161t\u011Bn\xED",popis:e=>`M\u011Bs\xEDc je pln\u011B osv\u011Btlen. Emoce jsou zes\xEDleny, intuice naost\u0159ena. To, co bylo zaseto, se projevuje. Je \u010Das slavit, vd\u011B\u010Dit \u2014 a v\u011Bdom\u011B propustit v\u0161e, co v\xE1m ji\u017E neslou\u017E\xED. Va\u0161e ${e.element.toLowerCase()} je dnes na vrcholu.`,prepList:["Sv\xED\u010Dka (zlat\xE1 nebo b\xEDl\xE1)","Pap\xEDr a tu\u017Eka","Sklenka vody","Bezpe\u010Dn\xE9 m\xEDsto (p\u0159\xEDpadn\u011B pro sp\xE1len\xED pap\xEDru)"],duration:"10\u201312 minut",kroky:[{title:"Uzem\u011Bn\xED",text:e=>`Rozsv\u011B\u0165te sv\xED\u010Dku. T\u0159ikr\xE1t zhluboka d\xFDchejte. C\xEDt\u011Bte plnou energii \xDApl\u0148ku \u2014 jak pronik\xE1 do ka\u017Ed\xE9 bu\u0148ky va\u0161eho t\u011Bla. Jste na vrcholu lun\xE1rn\xEDho cyklu. V\u0161e, co bylo zaseto, je nyn\xED viditeln\xE9. ${e.uzemeniVeta}`,subtext:"Uzem\u011Bn\xED v pln\xE9 energii"},{title:"Z\xE1m\u011Br",text:e=>`Vzpome\u0148te na z\xE1m\u011Bry ze za\u010D\xE1tku cyklu. Co se naplnilo? Co p\u0159i\u0161lo ne\u010Dekan\u011B? Bu\u010Fte vd\u011B\u010Dn\xED za oboje. Pak se zeptejte: "Co mus\xEDm pustit, aby mohl p\u0159ij\xEDt nov\xFD za\u010D\xE1tek?" Nechte ${e.focus} v\xE1m odpov\u011Bd\u011Bt bez cenzury.`,subtext:"Sklize\u0148 a v\u011Bdom\xE1 volba propu\u0161t\u011Bn\xED"},{title:"Vizualizace",text:e=>`Zav\u0159ete o\u010Di. P\u0159edstavte si st\u0159\xEDbrn\xE9 sv\u011Btlo \xDApl\u0148ku, jak pln\xED celou va\u0161i m\xEDstnost a pak i v\xE1s. Pak si p\u0159edstavte ${e.vizObraz}. Nechte toto sv\u011Btlo proj\xEDt ka\u017Edou bu\u0148kou \u2014 o\u010Distit, naplnit a osvobodit. D\xFDchejte sv\u011Btlo dovnit\u0159.`,subtext:"Vizualizace o\u010Disty a napln\u011Bn\xED"},{title:"Fyzick\xFD \xFAkon",text:e=>"Napi\u0161te na pap\xEDr, co chcete propustit \u2014 zvyk, my\u0161lenku, vztah, strach, p\u0159esv\u011Bd\u010Den\xED o sob\u011B. Pak pap\xEDr p\u0159etrhn\u011Bte na dv\u011B \u010D\xE1sti. Pokud m\xE1te mo\u017Enost, spalte jej bezpe\u010Dn\u011B. Nebo jej v\u011Bdom\u011B ho\u010Fte do ko\u0161e. Propou\u0161t\xEDte.",subtext:"Ritu\xE1ln\xED propu\u0161t\u011Bn\xED"},{title:"Mantra",text:e=>`T\u0159ikr\xE1t opakujte:

\u201EV ${e.mantraSlovo} a vd\u011B\u010Dnosti propou\u0161t\xEDm star\xE9.
Jsem voln\xFD/\xE1 a p\u0159ipraven\xFD/\xE1 \u2014 ${e.ruler} otev\xEDr\xE1 nov\xFD cyklus."`,subtext:"Opakujte t\u0159ikr\xE1t \u2014 s lehkost\xED a vd\u011B\u010Dnost\xED"},{title:"Uzav\u0159en\xED",text:e=>`Vezm\u011Bte sklenku vody a podr\u017Ete ji chv\xEDli v dlan\xEDch. P\u0159edstavte si, jak do n\xED proud\xED sv\u011Btlo \xDApl\u0148ku. Vypijte ji jako symbol p\u0159ijet\xED nov\xE9 energie. ${e.uzavreniVeta} Pod\u011Bkujte M\u011Bs\xEDci. Zhasn\u011Bte sv\xED\u010Dku.`,subtext:"Ritu\xE1l dokon\u010Den \u2014 cyklus se uzav\xEDr\xE1"}],journalPrompts:e=>["Co konkr\xE9tn\xEDho se v tomto lun\xE1rn\xEDm cyklu naplnilo nebo projevilo \u2014 i ne\u010Dekan\u011B?","Co propou\u0161t\xEDm a jak se c\xEDt\xEDm po tomto rozhodnut\xED? Co to uvoln\u011Bn\xED p\u0159inese?","Jak\xFD je prvn\xED z\xE1m\u011Br pro nov\xFD cyklus, kter\xFD brzy za\u010Dne?",e.journalQ]},"waning-gibbous":{nazevPrefix:"Ritu\xE1l vd\u011B\u010Dnosti",tema:"Ub\xFDvaj\xEDc\xED m\u011Bs\xEDc \u2014 sd\xEDlen\xED moudrosti a reflexe",popis:e=>`M\u011Bs\xEDc ub\xFDv\xE1 a energie se obrac\xED dovnit\u0159. Je \u010Das integrovat to, co \xDApln\u011Bk p\u0159inesl, a sd\xEDlet moudrost. Va\u0161e ${e.element.toLowerCase()} v\xE1s zve k hlubok\xE9 reflexi a p\u0159ed\xE1v\xE1n\xED.`,prepList:["Sv\xED\u010Dka","Den\xEDk nebo pap\xEDr","Tich\xE9 m\xEDsto","\u010Caj nebo tepl\xFD n\xE1poj (voliteln\u011B)"],duration:"8\u201310 minut",kroky:[{title:"Uzem\u011Bn\xED",text:e=>`Rozsv\u011B\u0165te sv\xED\u010Dku. T\u0159ikr\xE1t zhluboka d\xFDchejte s v\u011Bdom\xEDm, \u017Ee ub\xFDvaj\xEDc\xED sv\u011Btlo M\u011Bs\xEDce nese va\u0161i moudrost dom\u016F. Dovolte si zpomalit \u2014 \u017E\xE1dn\xFD sp\u011Bch, \u017E\xE1dn\xE9 n\xE1roky. Jen p\u0159\xEDtomnost. ${e.uzemeniVeta}`,subtext:"Uzem\u011Bn\xED v reflexi a klidu"},{title:"Z\xE1m\u011Br",text:e=>`Zam\u011B\u0159te se na ${e.focus}. Zeptejte se: "\u010Cemu jsem se v tomto cyklu nau\u010Dil/a? Jakou moudrost chci n\xE9st d\xE1l \u2014 a jakou sd\xEDlet s ostatn\xEDmi?" S\xEDdlejte v tichu, dokud nep\u0159ijde odpov\u011B\u010F.`,subtext:"Integrov\xE1n\xED moudrosti cyklu"},{title:"Vizualizace",text:e=>`Zav\u0159ete o\u010Di. P\u0159edstavte si ${e.vizObraz}. Pak si p\u0159edstavte, jak tuto kvalitu \u2014 va\u0161i moudrost z cyklu \u2014 p\u0159ed\xE1v\xE1te jako dar n\u011Bkomu bl\xEDzk\xE9mu. Jak se tv\xE1\u0159\xED, kdy\u017E ji p\u0159ijme? Jak se c\xEDt\xEDte vy?`,subtext:"Vizualizace sd\xEDlen\xED a p\u0159ed\xE1n\xED"},{title:"Fyzick\xFD \xFAkon",text:e=>"Napi\u0161te 3 v\u011Bci, za kter\xE9 jste v tomto cyklu hluboce vd\u011B\u010Dn\xED. Pak napi\u0161te 1 konkr\xE9tn\xED moudrost nebo zku\u0161enost, kterou sd\xEDl\xEDte s n\u011Bk\xFDm bl\xEDzk\xFDm \u2014 je\u0161t\u011B tento t\xFDden. Konkr\xE9tn\u011B: s k\xFDm a co.",subtext:"Vd\u011B\u010Dnost stvrzen\xE1 a sd\xEDlen\xED napl\xE1novan\xE9"},{title:"Mantra",text:e=>`T\u0159ikr\xE1t opakujte:

\u201EV ${e.mantraSlovo} a vd\u011B\u010Dnosti sd\xEDl\xEDm sv\u011Btlo, kter\xE9 jsem p\u0159ijal/a.
M\xE1 moudrost roste p\u0159ed\xE1v\xE1n\xEDm \u2014 tak jako ${e.ruler} napl\u0148uje sv\u016Fj cyklus."`,subtext:"Opakujte t\u0159ikr\xE1t"},{title:"Uzav\u0159en\xED",text:e=>`Pod\u011Bkujte za v\u0161e, co tento cyklus p\u0159inesl \u2014 dobr\xE9 i n\xE1ro\u010Dn\xE9. Oboj\xED bylo va\u0161\xEDm u\u010Ditelem. ${e.uzavreniVeta} Zhasn\u011Bte sv\xED\u010Dku. Nesete moudrost d\xE1l \u2014 to je nejvz\xE1cn\u011Bj\u0161\xED v\u011Bc, co m\u016F\u017Eete d\xE1t.`,subtext:"Ritu\xE1l dokon\u010Den"}],journalPrompts:e=>["Jak\xE1 moudrost z tohoto cyklu m\u011B nejv\xEDce p\u0159ekvapila nebo zas\xE1hla?","Komu mohu p\u0159edat to, co jsem se nau\u010Dil/a? Jak to ud\u011Bl\xE1m konkr\xE9tn\u011B?","Za co jsem nejhloub\u011Bji vd\u011B\u010Dn\xFD/\xE1 \u2014 i za to, co bylo t\u011B\u017Ek\xE9?",e.journalQ]},"last-quarter":{nazevPrefix:"Ritu\xE1l \u010Dist\u011Bn\xED",tema:"Posledn\xED \u010Dtvr\u0165 \u2014 propu\u0161t\u011Bn\xED a p\u0159\xEDprava prostoru",popis:e=>`M\u011Bs\xEDc se vrac\xED k temnot\u011B. Je \u010Das hlubok\xE9ho \xFAklidu \u2014 fyzick\xE9ho, emocion\xE1ln\xEDho i ment\xE1ln\xEDho. Va\u0161e ${e.element.toLowerCase()} v\xE1m pom\xE1h\xE1 jasn\u011B vid\u011Bt, co n\xE9st d\xE1l a co v\u011Bdom\u011B pustit.`,prepList:["Sv\xED\u010Dka","Pap\xEDr a tu\u017Eka","Tich\xE9 m\xEDsto"],duration:"8\u201310 minut",kroky:[{title:"Uzem\u011Bn\xED",text:e=>`Rozsv\u011B\u0165te sv\xED\u010Dku. T\u0159ikr\xE1t zhluboka d\xFDchejte. S ka\u017Ed\xFDm v\xFDdechem si p\u0159edstavte, jak vydechujete v\u0161e star\xE9, p\u0159ebyte\u010Dn\xE9 a unavuj\xEDc\xED. C\xEDt\xEDte se leh\u010D\xED s ka\u017Ed\xFDm dechem. Ub\xFDvaj\xEDc\xED M\u011Bs\xEDc nese star\xE9 pry\u010D. ${e.uzemeniVeta}`,subtext:"Uzem\u011Bn\xED v o\u010Dist\u011B"},{title:"Z\xE1m\u011Br",text:e=>`Zeptejte se sami sebe: "Co v m\xE9m \u017Eivot\u011B zab\xEDr\xE1 m\xEDsto, ani\u017E by mi p\u0159in\xE1\u0161elo radost nebo smysl?" Nechte ${e.focus} v\xE1m pomoci rozli\u0161it, co je skute\u010Dn\u011B va\u0161e \u2014 a co si jen nesete ze zvyku nebo ze strachu.`,subtext:"Inventura p\u0159ebyte\u010Dn\xE9ho"},{title:"Vizualizace",text:e=>`Zav\u0159ete o\u010Di. P\u0159edstavte si ${e.vizObraz}. Pak si p\u0159edstavte, jak p\u0159es tento obraz proch\xE1z\xED \u010Dist\xFD v\xEDtr. Odn\xE1\u0161\xED v\u0161e, co v\xE1m neslou\u017E\xED \u2014 bez dramatu, bez l\xEDtosti. Prostor po nich je sv\u011Btl\xFD, \u010Dist\xFD a p\u0159ipraven\xFD.`,subtext:"Vizualizace \u010Dist\xE9ho prostoru"},{title:"Fyzick\xFD \xFAkon",text:e=>'Napi\u0161te na pap\xEDr 3 v\u011Bci, kter\xE9 v\u011Bdom\u011B propou\u0161t\xEDte \u2014 my\u0161lenky, n\xE1vyky, p\u0159edm\u011Bty nebo vztahy, kter\xE9 v\xE1s ji\u017E nevy\u017Eivuj\xED. Pro ka\u017Edou napi\u0161te: "Propou\u0161t\xEDm _____, proto\u017Ee _____." Pak pap\xEDr p\u0159etrhn\u011Bte nebo vyho\u010Fte.',subtext:"V\u011Bdom\xE9 a konkr\xE9tn\xED propu\u0161t\u011Bn\xED"},{title:"Mantra",text:e=>`T\u0159ikr\xE1t opakujte:

\u201EV ${e.mantraSlovo} a jasnosti \u010Dist\xEDm sv\u016Fj prostor.
To, co odch\xE1z\xED, vytv\xE1\u0159\xED m\xEDsto pro nov\xE9 \u2014 a ${e.ruler} mi d\xE1v\xE1 jasnost vid\u011Bt, co si n\xE9st d\xE1l."`,subtext:"Opakujte t\u0159ikr\xE1t"},{title:"Uzav\u0159en\xED",text:e=>`Pod\u011Bkujte si za odvahu pustit to, co bylo t\u0159eba. Ka\u017Ed\xFD odchod je pozv\xE1nka pro p\u0159\xEDchod. ${e.uzavreniVeta} Zhasn\u011Bte sv\xED\u010Dku. V\xE1\u0161 prostor \u2014 vnit\u0159n\xED i vn\u011Bj\u0161\xED \u2014 je \u010Dist\u0161\xED.`,subtext:"Ritu\xE1l dokon\u010Den"}],journalPrompts:e=>["Jak se c\xEDt\xEDm po tomto v\u011Bdom\xE9m propu\u0161t\u011Bn\xED? Co se pohnulo?","Co si s sebou do nov\xE9ho cyklu beru jako pou\u010Den\xED \u2014 ne jako b\u0159emeno?","Jak\xFD prostor jsem v sob\u011B dnes otev\u0159el/a pro nov\xE9?",e.journalQ]},"waning-crescent":{nazevPrefix:"Ritu\xE1l ticha",tema:"Ub\xFDvaj\xEDc\xED srpek \u2014 obnova, odpo\u010Dinek a p\u0159\xEDprava",popis:e=>`M\u011Bs\xEDc t\xE9m\u011B\u0159 zmizel z oblohy. Cyklus se uzav\xEDr\xE1. Toto je nejintrovertovan\u011Bj\u0161\xED f\xE1ze \u2014 \u010Das skute\u010Dn\xE9ho odpo\u010Dinku, regenerace a tich\xE9 p\u0159\xEDpravy. Va\u0161e ${e.element.toLowerCase()} si zaslou\u017E\xED klid.`,prepList:["Sv\xED\u010Dka","Pohodln\xE9 m\xEDsto k sezen\xED nebo lehnut\xED","Tich\xE1 m\xEDstnost bez ru\u0161iv\xFDch vliv\u016F"],duration:"7\u201310 minut",kroky:[{title:"Uzem\u011Bn\xED",text:e=>`Rozsv\u011B\u0165te sv\xED\u010Dku. Lehn\u011Bte si nebo pohodln\u011B sedn\u011Bte. T\u0159ikr\xE1t zhluboka d\xFDchejte bez jak\xE9hokoli z\xE1m\u011Bru \u2014 jen \u010Dist\xE9 d\xFDch\xE1n\xED. Dovolte sv\xE9mu t\u011Blu a mysli odpo\u010D\xEDvat bez n\xE1roku na v\xFDkon. ${e.uzemeniVeta}`,subtext:"Uzem\u011Bn\xED v hlubok\xE9m klidu"},{title:"Z\xE1m\u011Br",text:e=>`Dne\u0161n\xED z\xE1m\u011Br je nejjednodu\u0161\u0161\xED ze v\u0161ech: dovolit si opravdu odpo\u010Dinout. Zeptejte se ti\u0161e: "Co m\xE9 t\u011Blo a du\u0161e pot\u0159ebuj\xED, abych se zotavil/a a obnovil/a?" Nechte ${e.focus} uk\xE1zat cestu k obnov\u011B.`,subtext:"Z\xE1m\u011Br v odpo\u010Dinku bez v\xFD\u010Ditek"},{title:"Vizualizace",text:e=>`Zav\u0159ete o\u010Di. P\u0159edstavte si ${e.vizObraz}. Tento obraz se pomalu rozpl\xFDv\xE1, jak M\u011Bs\xEDc ub\xFDv\xE1. Nechte mysl spo\u010Dinout v tichu \u2014 \u017E\xE1dn\xE9 pl\xE1ny, \u017E\xE1dn\xE9 \xFAkoly, \u017E\xE1dn\xE1 anal\xFDza. Jen byt\xED v p\u0159\xEDtomn\xE9m okam\u017Eiku.`,subtext:"Vizualizace hlubok\xE9ho ticha"},{title:"Fyzick\xFD \xFAkon",text:e=>"Z\u016Fsta\u0148te 3 minuty v absolutn\xEDm tichu. \u017D\xE1dn\xFD telefon, \u017E\xE1dn\xE1 hudba, \u017E\xE1dn\xE9 zpr\xE1vy. Jen ticho a sv\xED\u010Dka. Pokud p\u0159ijdou my\u0161lenky, p\u0159ijm\u011Bte je laskav\u011B a nechte odej\xEDt jako mraky po obloze.",subtext:"3 minuty v\u011Bdom\xE9ho ticha"},{title:"Mantra",text:e=>`T\u0159ikr\xE1t opakujte \u2014 pomalu, t\xE9m\u011B\u0159 v \u0161epotu:

\u201EV ${e.mantraSlovo} a tichu se obnovuji.
Nov\xFD cyklus za\u010D\xEDn\xE1 brzy \u2014 ${e.ruler} p\u0159ipravuje nov\xFD za\u010D\xE1tek."`,subtext:"\u0160eptejte t\u0159ikr\xE1t \u2014 jemn\u011B"},{title:"Uzav\u0159en\xED",text:e=>`Pod\u011Bkujte si za to, \u017Ee jste si dovolili zastavit. Odpo\u010Dinek nen\xED slabost \u2014 je to p\u0159\xEDprava pro v\u0161e, co p\u0159ijde. ${e.uzavreniVeta} Zhasn\u011Bte sv\xED\u010Dku. Novolun\u011Bn\xED se bl\xED\u017E\xED a vy budete p\u0159ipraveni.`,subtext:"Ritu\xE1l dokon\u010Den \u2014 cyklus se uzav\xEDr\xE1"}],journalPrompts:e=>["Jak se c\xEDt\xEDm, kdy\u017E si dovol\xEDm opravdu odpo\u010Dinout \u2014 bez v\xFD\u010Ditek?","Co z tohoto lun\xE1rn\xEDho cyklu si nesu jako dar a pou\u010Den\xED do nov\xE9ho?","Co by novolun\xED mohlo p\u0159in\xE9st, kdyby v\u0161e bylo mo\u017En\xE9?",e.journalQ]}};function u(e,i){const o=n[e]||n["full-moon"],t=a[i]||a.beran;return{nazev:`${o.nazevPrefix} \u2014 ${t.name}`,signName:t.name,signEmoji:t.emoji,signElement:t.element,signRuler:t.ruler,signBarva:t.barva,phaseSlug:e,signSlug:i,phaseTema:o.tema,popis:o.popis(t),prepList:o.prepList,duration:o.duration,kroky:o.kroky.map((s,l)=>({cislo:l+1,title:s.title,text:s.text(t),subtext:s.subtext})),journalPrompts:o.journalPrompts(t)}}function r(){return a}function v(){return Object.keys(n)}window.RitualContent={getRitual:u,getAllSigns:r,getAllPhases:v}})();})();
